import React, { useState, useEffect } from "react";
import { motion, useInView } from "framer-motion";
import { useRef } from "react";
import "./index.css";

export default function App() {
  const [theme, setTheme] = useState("dark");

  const toggleTheme = () => {
    setTheme(theme === "dark" ? "light" : "dark");
  };

  return (
    <div className={`${theme === "dark"
        ? "bg-gradient-to-br from-black via-gray-900 to-black text-white"
        : "bg-gradient-to-br from-gray-100 via-gray-200 to-gray-50 text-gray-900"
      } min-h-screen transition-all duration-500`}>

      <Navbar toggleTheme={toggleTheme} />
      <Hero />
      <Stats />
      <Skills />
      <Experience />
      <Projects />
      <Contact />
      <Footer />
    </div>
  );
}

// NAVBAR
function Navbar({ toggleTheme }) {
  return (
    <div className="sticky top-0 z-50 backdrop-blur-xl bg-white/5 border-b border-white/10">
      <div className="max-w-7xl mx-auto flex justify-between items-center px-6 py-4">
        <h1 className="text-xl font-bold tracking-widest">Muhammad Kashif</h1>

        <div className="hidden md:flex gap-6">
          <a href="#exp">Experience</a>
          <a href="#projects">Projects</a>
          <a href="#contact">Contact</a>
        </div>

        <button onClick={toggleTheme} className="px-3 py-1 border rounded-lg">
          Toggle
        </button>
      </div>
    </div>
  );
}

// HERO
function Hero() {
  return (
    <div className="text-center py-32">
      <motion.h1
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        className="text-6xl font-bold bg-gradient-to-r from-blue-400 to-purple-500 text-transparent bg-clip-text"
      >
        Muhammad Kashif
      </motion.h1>

      <p className="mt-6 text-xl text-gray-400">
        Full Stack Engineer | Real-Time Systems Specialist
      </p>

      <div className="mt-8 flex justify-center gap-4">
        <a href="#projects"><button className="px-6 py-2 bg-blue-600 rounded">Projects</button></a>
        <a href="#contact"><button className="px-6 py-2 border rounded">Contact</button></a>
      </div>

      <div className="mt-6 flex justify-center gap-4">
        <a href="https://linkedin.com" target="_blank"><button className="px-4 py-2 border">LinkedIn</button></a>
        <a href="https://github.com" target="_blank"><button className="px-4 py-2 border">GitHub</button></a>
      </div>
    </div>
  );
}

// 🔥 COUNT UP HOOK
function useCountUp(end, duration = 2000, startAnimation) {
  const [count, setCount] = useState(0);

  useEffect(() => {
    if (!startAnimation) return;

    let start = 0;
    const increment = end / (duration / 16);

    const counter = setInterval(() => {
      start += increment;
      if (start >= end) {
        setCount(end);
        clearInterval(counter);
      } else {
        setCount(Math.floor(start));
      }
    }, 16);

    return () => clearInterval(counter);
  }, [startAnimation, end, duration]);

  return count;
}

// STATS (Animated on scroll)
function Stats() {
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true });

  const years = useCountUp(3, 500, isInView);
  const projects = useCountUp(10, 500, isInView);

  return (
    <div ref={ref} className="py-20 text-center">
      <div className="flex justify-center gap-10 flex-wrap">

        <div>
          <h2 className="text-4xl font-bold">{years}+</h2>
          <p className="text-gray-400">Years Experience</p>
        </div>

        <div>
          <h2 className="text-4xl font-bold">{projects}+</h2>
          <p className="text-gray-400">Projects</p>
        </div>

        <div>
          <h2 className="text-4xl font-bold">Expert</h2>
          <p className="text-gray-400">Real-Time Systems</p>
        </div>

      </div>
    </div>
  );
}

// SKILLS
function Skills() {
  const skills = [
    "React",
    "Node.js",
    "WebSockets",
    "MongoDB",
    "Leaflet",
    "C",
    "C++",
    "WebGL"
  ];

  return (
    <div className="py-20 text-center">
      <h2 className="text-3xl font-bold mb-10">Skills</h2>
      <div className="flex justify-center gap-4 flex-wrap">
        {skills.map((skill, i) => (
          <span key={i} className="px-4 py-2 border rounded-full">
            {skill}
          </span>
        ))}
      </div>
    </div>
  );
}

// EXPERIENCE
// function Experience() {
//   return (
//     <div id="exp" className="py-20 px-10">
//       <h2 className="text-3xl font-bold text-center mb-10">Experience</h2>
//       <p className="text-center max-w-2xl mx-auto text-gray-400">
//         3+ years building real-time systems, map-based applications, and scalable web apps.
//       </p>
//     </div>
//   );
// }

// // PROJECTS
// function Projects() {
//   return (
//     <div id="projects" className="py-20 px-10">
//       <h2 className="text-3xl font-bold text-center mb-10">Projects</h2>

//       <div className="grid md:grid-cols-3 gap-6">
//         <ProjectCard title="Air Traffic App" link="#" />
//         <ProjectCard title="Map Drawing Tool" link="#" />
//         <ProjectCard title="Sensor System" link="#" />
//       </div>
//     </div>
//   );
// }

// function ProjectCard({ title, link }) {
//   return (
//     <a href={link} target="_blank" rel="noreferrer">
//       <div className="relative group p-6 border rounded-xl hover:scale-105 transition">
//         <h3 className="text-xl font-bold">{title}</h3>

//         <div className="opacity-0 group-hover:opacity-100 absolute inset-0 bg-black/70 flex items-center justify-center rounded-xl transition">
//           <span>View Project →</span>
//         </div>
//       </div>
//     </a>
//   );
// }


function Experience({ theme }) {
  return (
    <div id="exp" className="px-10 py-24">
      <h2
        className={`text-4xl font-bold mb-16 text-center ${theme === "dark" ? "text-white" : "text-gray-900"
          }`}
      >
        Experience
      </h2>

      <div className="max-w-6xl mx-auto grid md:grid-cols-2 gap-8">
        {/* Card 1 */}
        <motion.div
          initial={{ opacity: 0, y: 50 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.8 }}
          className={`group p-8 rounded-3xl backdrop-blur-xl border shadow-xl hover:scale-105 transition-transform ${theme === "dark"
              ? "bg-gradient-to-br from-blue-800/40 via-black/40 to-blue-900/40 border-white/10 text-gray-200"
              : "bg-gradient-to-br from-blue-200/40 via-gray-100/40 to-blue-300/40 border-gray-300 text-gray-900"
            }`}
        >
          <div className="flex items-center mb-4">
            <div className="bg-blue-600 p-3 rounded-full mr-4">
              <svg
                xmlns="http://www.w3.org/2000/svg"
                className="h-6 w-6 text-white"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M3 7l6 6-6 6M21 7l-6 6 6 6"
                />
              </svg>
            </div>
            <h3 className="text-2xl font-semibold">Real-Time Air Traffic & Sensor Systems</h3>
          </div>
          <p className="mb-4 leading-relaxed">
            Led integration of multiple <strong>sensors</strong> into a large-scale system, coordinating with vendors and cross-functional teams. Managed real-time pipelines with <strong>WebSockets, TCP, UDP</strong>. Built high-availability <strong>React-Leaflet</strong> apps with dynamic map markers and 24/7 uptime.
          </p>
          <div className="flex flex-col gap-2">
            <div><span className="font-semibold text-blue-400">Technologies:</span> React, React-Leaflet, WebSockets, TCP, UDP</div>
            <div><span className="font-semibold text-blue-400">Achievements:</span> Real-time monitoring, low-latency visualization, dynamic markers</div>
          </div>
        </motion.div>

        {/* Card 2 */}
        <motion.div
          initial={{ opacity: 0, y: 50 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.8, delay: 0.2 }}
          className={`group p-8 rounded-3xl backdrop-blur-xl border shadow-xl hover:scale-105 transition-transform ${theme === "dark"
              ? "bg-gradient-to-br from-purple-800/40 via-black/40 to-purple-900/40 border-white/10 text-gray-200"
              : "bg-gradient-to-br from-purple-200/40 via-gray-100/40 to-purple-300/40 border-gray-300 text-gray-900"
            }`}
        >
          <div className="flex items-center mb-4">
            <div className="bg-purple-600 p-3 rounded-full mr-4">
              <svg
                xmlns="http://www.w3.org/2000/svg"
                className="h-6 w-6 text-white"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
              >
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
              </svg>
            </div>
            <h3 className="text-2xl font-semibold">Full Stack Web Applications</h3>
          </div>
          <p className="mb-4 leading-relaxed">
            Developed scalable web apps with <strong>React, Node.js, Express</strong>. Built interactive map drawing tools for polygons, lines, and markers with database integration. Ensured responsive, low-latency performance and agile development workflow.
          </p>
          <div className="flex flex-col gap-2">
            <div><span className="font-semibold text-purple-400">Technologies:</span> React, Node.js, Express, MongoDB</div>
            <div><span className="font-semibold text-purple-400">Achievements:</span> Interactive maps, responsive UI, real-time data capture</div>
          </div>
        </motion.div>
      </div>
    </div>
  );
}

// ---------------- PROJECTS ----------------
function Projects({ theme }) {
  return (
    <div id="projects" className="px-10 py-24">
      <h2
        className={`text-4xl font-bold mb-16 text-center ${theme === "dark" ? "text-white" : "text-gray-900"
          }`}
      >
        Projects
      </h2>

      <div className="max-w-6xl mx-auto grid md:grid-cols-3 gap-8">
        {/* Project 1 */}
        <ProjectCard
          theme={theme}
          title="Air Traffic Application"
          desc="High-availability React-Leaflet app for real-time air traffic monitoring with dynamic markers and live updates."
          technologies="React, React-Leaflet, WebSockets, TCP, UDP"
          features="Live updates, dynamic markers, 24/7 uptime, low-latency visualization"
          color="blue"
        />
        {/* Project 2 */}
        <ProjectCard
          theme={theme}
          title="Map Drawing Tools"
          desc="Interactive map tools for creating polygons, lines, and markers with database integration and real-time coordinates."
          technologies="React, Leaflet, MongoDB, Node.js"
          features="Polygon drawing, real-time coordinates, tooltips, markers, layer management"
          color="purple"
        />
        {/* Project 3 */}
        <ProjectCard
          theme={theme}
          title="Sensor Integration"
          desc="Integrated multiple sensors with web applications, ensuring seamless real-time data flow and optimized performance."
          technologies="React, WebSockets, TCP, UDP, Node.js"
          features="Real-time sensor data, live visualization, low-latency updates, 24/7 high availability"
          color="green"
        />
      </div>
    </div>
  );
}

function ProjectCard({ theme, title, desc, technologies, features, color }) {
  const colors = {
    blue: "from-blue-800/40 via-black/40 to-blue-900/40 dark:border-white/10",
    purple: "from-purple-800/40 via-black/40 to-purple-900/40 dark:border-white/10",
    green: "from-green-800/40 via-black/40 to-green-900/40 dark:border-white/10",
  };
  const lightColors = {
    blue: "from-blue-200/40 via-gray-100/40 to-blue-300/40 border-gray-300",
    purple: "from-purple-200/40 via-gray-100/40 to-purple-300/40 border-gray-300",
    green: "from-green-200/40 via-gray-100/40 to-green-300/40 border-gray-300",
  };
  return (
    <motion.div
      initial={{ opacity: 0, y: 50 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true }}
      transition={{ duration: 0.8 }}
      className={`group p-8 rounded-3xl backdrop-blur-xl border shadow-xl hover:scale-105 transition-transform ${theme === "dark" ? colors[color] + " text-gray-200" : lightColors[color] + " text-gray-900"
        }`}
    >
      <div className="flex items-center mb-4">
        <div className={`bg-${color}-600 p-3 rounded-full mr-4`}>
          <svg
            xmlns="http://www.w3.org/2000/svg"
            className="h-6 w-6 text-white"
            fill="none"
            viewBox="0 0 24 24"
            stroke="currentColor"
          >
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
          </svg>
        </div>
        <h3 className="text-2xl font-semibold">{title}</h3>
      </div>
      <p className="mb-4 leading-relaxed">{desc}</p>
      <div className="flex flex-col gap-2">
        <div><span className="font-semibold text-blue-400">Technologies:</span> {technologies}</div>
        <div><span className="font-semibold text-blue-400">Features:</span> {features}</div>
      </div>
    </motion.div>
  );
}

// CONTACT
function Contact() {
  return (
    <div id="contact" className="py-20 px-10">
      <h2 className="text-3xl font-bold text-center mb-10">Contact</h2>

      <form className="max-w-xl mx-auto space-y-4">
        <input placeholder="Name" className="w-full p-3 border rounded" />
        <input placeholder="Email" className="w-full p-3 border rounded" />
        <textarea placeholder="Message" className="w-full p-3 border rounded" />
        <button className="w-full bg-blue-600 py-3 rounded">Send</button>
      </form>
    </div>
  );
}

// FOOTER
function Footer() {
  return (
    <div className="text-center py-6 border-t mt-10">
      <p className="text-gray-400">© 2026 Muhammad Kashif</p>
    </div>
  );
}
